'use strict';

/**
 * generate-assets-bundle.js — Build-time asset bundler
 *
 * Reads all runtime-loaded assets (fonts, SVGs, vendor JS, compiled CSS)
 * and writes src/assets-bundle.ts with named string exports.
 *
 * This module is what src/mcp-server.ts imports when running as a compiled
 * binary where __dirname-relative paths are unavailable.
 *
 * Usage:
 *   node scripts/generate-assets-bundle.js
 *
 * Output:
 *   src/assets-bundle.ts
 */

const fs   = require('node:fs');
const path = require('node:path');

const ROOT = path.resolve(__dirname, '..');
const OUT  = path.join(ROOT, 'src', 'assets-bundle.ts');

/**
 * Read a file and return its contents base64-encoded.
 * @param {string} filePath
 * @returns {string}
 */
function readBase64(filePath) {
  const data = fs.readFileSync(filePath);
  return data.toString('base64');
}

/**
 * Read a file and return its contents as a UTF-8 string.
 * @param {string} filePath
 * @returns {string}
 */
function readUtf8(filePath) {
  return fs.readFileSync(filePath, 'utf8');
}

const assets = {
  FONT_REGULAR_B64:  readBase64(path.join(ROOT, 'assets/fonts/Inter-Regular.woff2')),
  FONT_SEMIBOLD_B64: readBase64(path.join(ROOT, 'assets/fonts/Inter-SemiBold.woff2')),
  FONT_BLACK_B64:    readBase64(path.join(ROOT, 'assets/fonts/Inter-Black.woff2')),
  MODULAR_LOGO_SVG:  readUtf8(path.join(ROOT, 'assets/svg/modular-logo.svg')),
  PALM_ICON_SVG:     readUtf8(path.join(ROOT, 'assets/svg/palm-icon.svg')),
  APEXCHARTS_JS:     readUtf8(path.join(ROOT, 'vendor/apexcharts.min.js')),
  TAILWIND_CSS:      readUtf8(path.join(ROOT, 'styles/dashboard.out.css')),
};

const lines = [
  '// AUTO-GENERATED by scripts/generate-assets-bundle.js — do not edit manually',
];

for (const [key, value] of Object.entries(assets)) {
  lines.push(`export const ${key} = ${JSON.stringify(value)};`);
}

const output = lines.join('\n') + '\n';

// Ensure src/ directory exists
const srcDir = path.join(ROOT, 'src');
if (!fs.existsSync(srcDir)) {
  fs.mkdirSync(srcDir, { recursive: true });
}

fs.writeFileSync(OUT, output, 'utf8');
console.error('[generate-assets-bundle] wrote src/assets-bundle.ts (' + Buffer.byteLength(output) + ' bytes)');
